let results = [];

// n8n'den gelen her bir ana öğeyi dönüyoruz
for (const item of items) {
  const raw = item.json;

  // Close CRM veriyi 'data' array'i içinde gönderir.
  // Diğerleri (Salesforce/HubSpot) direkt liste gönderir.
  // Eğer 'data' varsa onu kullan, yoksa öğeyi bir liste içine al.
  const records = (raw.data && Array.isArray(raw.data)) ? raw.data : [raw];

  for (const src of records) {
    const p = src.properties || {};

    // Değer bir objeyse (HubSpot) .value kısmını al, değilse direkt döndür
    const getValue = (val) => {
      if (val && typeof val === 'object' && val.hasOwnProperty('value')) {
        return val.value;
      }
      return val;
    };

    // DOMAIN TESPİTİ
    const domain =
      getValue(src.Website) ||      // Salesforce
      getValue(src.url) ||          // Close CRM
      getValue(p["domain"]) ||      // HubSpot
      getValue(p["website"]) ||     // HubSpot Alternatif
      getValue(src.domain) ||       // Genel
      getValue(src.website) ||      // Genel
      "";

    // ID TESPİTİ
    const companyId =
      getValue(src.Id) ||           // Salesforce
      getValue(src.id) ||           // Close & HubSpot (Yeni)
      getValue(src.objectId) ||     // HubSpot (Eski)
      getValue(p["hs_object_id"]) ||
      "";

    // Eğer ID veya Domain ikisi de boşsa bu kaydı ekleme (temizlik)
    if (companyId || domain) {
      results.push({
        json: {
          companyId: String(companyId),
          domain: domain
        }
      });
    }
  }
}

return results;
